from flask import Flask, request, jsonify
import redis
import os
import ssl

app = Flask(__name__)

# Redis connection settings
REDIS_NODES = [
    {"host": "redis-node-1", "port": 6379},
    {"host": "redis-node-2", "port": 6379},
    {"host": "redis-node-3", "port": 6379},
]

# Create a Redis connection pool
def create_redis_pool():
    return redis.ConnectionPool(
        host=REDIS_NODES[0]['host'],
        port=REDIS_NODES[0]['port'],
        ssl=True,
        ssl_cert_reqs=ssl.CERT_REQUIRED,
        ssl_ca_certs=os.environ.get('REDIS_CA_CERT_PATH'),
    )

redis_pool = create_redis_pool()
redis_client = redis.Redis(connection_pool=redis_pool)

@app.route('/store', methods=['POST'])
def store_data():
    data = request.json
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 3600)  # Default TTL of 1 hour

    if not key or not value:
        return jsonify({"error": "Key and value are required"}), 400

    redis_client.setex(key, ttl, value)
    return jsonify({"message": "Data stored successfully"}), 201

@app.route('/retrieve/<key>', methods=['GET'])
def retrieve_data(key):
    value = redis_client.get(key)
    if value is None:
        return jsonify({"error": "Key not found"}), 404
    return jsonify({"key": key, "value": value.decode('utf-8')}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)